      return cleaned.length > 0 ? cleaned : val;
  };

  const getStatusColor = (msg: string) => {
      if (!msg) return "text-gray-600 bg-gray-50 border-gray-200";
      const lower = msg.toLowerCase();
      if (lower.includes('buy') || lower.includes('undervalued') || lower.includes('good') || lower.includes('bull')) 
