                            {tile.label}
                        </span>
                        {tile.title && (
                             <div className="relative group/tooltip">
                                 <Info size={10} className="opacity-40 cursor-help" />
                                 <div className="absolute right-0 top-4 w-40 bg-gray-800 text-white text-[9px] p-2 rounded shadow-lg z-20 hidden group-hover/tooltip:block pointer-events-none">
                                     {tile.title}
                                 </div>
                             </div>
                        )}
                    </div>

                    <div className="flex items-baseline gap-1 mt-1">
                        <span className="text-lg md:text-xl font-bold leading-none">
                            {cleanValue(tile.value)}
