import React from 'react';
import { TrendingUp, TrendingDown, Minus, ArrowRight } from 'lucide-react';

interface Insight {
  type: string;
  message: string;
}

interface QuarterlyHoldingsCardProps {
  data: { insights: Insight[] } | null;
}

const QuarterlyHoldingsCard: React.FC<QuarterlyHoldingsCardProps> = ({ data }) => {
  if (!data || !data.insights || data.insights.length === 0) {
      return (
        <div className="h-full flex items-center justify-center text-xs text-gray-400 italic">
          No Quarterly Data
        </div>
      );
  }

  const getIcon = (type: string) => {
      const t = type.toLowerCase();
      if (t === 'positive') return <TrendingUp size={14} className="text-green-600" />;
      if (t === 'negative') return <TrendingDown size={14} className="text-red-600" />;
      return <Minus size={14} className="text-gray-400" />;
  };

  const getBgClass = (type: string) => {
      const t = type.toLowerCase();
      if (t === 'positive') return 'bg-green-50 border-green-100';
      if (t === 'negative') return 'bg-red-50 border-red-100';
      return 'bg-gray-50 border-gray-100';
  };

  // Helper to make percentages bold
  const formatMessage = (msg: string) => {
      const parts = msg.split(/(\d+(?:\.\d+)?%)/);
      return parts.map((part, i) => {
          if (part.includes('%')) {
              return <span key={i} className="font-bold text-gray-900">{part}</span>;
          }
          return <span key={i}>{part}</span>;
      });
  };

  return (
    <div className="h-full overflow-y-auto custom-scrollbar p-1">
        <div className="space-y-2">
            {data.insights.map((insight, idx) => (
                <div key={idx} className={`p-2 rounded border flex items-start gap-2.5 ${getBgClass(insight.type)}`}>
                    <div className="mt-0.5 shrink-0 bg-white p-1 rounded-full shadow-sm">
                        {getIcon(insight.type)}
                    </div>
                    <div className="text-[10px] leading-relaxed text-gray-700 font-medium">
                        {formatMessage(insight.message)}
                    </div>
                </div>
            ))}
        </div>
    </div>
  );
};

export default QuarterlyHoldingsCard;

import React from 'react';
import { Calendar, Layers, FileText } from 'lucide-react';

interface BulkBlockDealsCardProps {
  data: {
    title: string;
    summary: string;
    description: string;
  } | null;
}

const BulkBlockDealsCard: React.FC<BulkBlockDealsCardProps> = ({ data }) => {
  if (!data || !data.summary) {
      return (
        <div className="h-full flex items-center justify-center text-xs text-gray-400 italic">
          No Recent Deals
        </div>
      );
  }

  // Basic regex to wrap numbers and dates in bold tags
  const highlightKeyInfo = (text: string) => {
      // Matches dates like Nov. 21, 2025 or numbers like 352,107 or prices like Rs 1534.00
      const parts = text.split(/(\b[A-Z][a-z]{2}\.\s\d{1,2},\s\d{4}\b|\b[\d,]+\s(?:shares)|Rs\s[\d,.]+)/g);
      return parts.map((part, i) => {
          if (part.match(/(\b[A-Z][a-z]{2}\.\s\d{1,2},\s\d{4}\b|\b[\d,]+\s(?:shares)|Rs\s[\d,.]+)/)) {
              return <span key={i} className="font-bold text-indigo-900 bg-indigo-50 px-1 rounded">{part}</span>;
          }
          return part;
      });
  };

  return (
    <div className="h-full flex flex-col justify-between overflow-y-auto custom-scrollbar p-1 gap-3">
        {/* Latest Deal Highlight */}
        <div className="flex-1">
            <div className="flex items-center gap-1.5 mb-2 text-indigo-600">
                <Layers size={14} />
                <span className="text-[10px] font-bold uppercase tracking-wider">Latest Deal Summary</span>
            </div>
            <div className="p-3 bg-white rounded-lg border border-indigo-100 shadow-sm text-sm text-gray-700 leading-relaxed">
                {highlightKeyInfo(data.summary)}
            </div>
        </div>

        {/* Description / Footer */}
        {data.description && (
            <div className="mt-auto border-t border-gray-100 pt-2">
                 <div className="flex gap-1.5 items-start">
                    <FileText size={12} className="text-gray-400 mt-0.5 shrink-0" />
                    <p className="text-[9px] text-gray-400 leading-normal line-clamp-3">
                        {data.description}
                    </p>
                 </div>
            </div>
        )}
    </div>
  );
};

export default BulkBlockDealsCard;

import React from 'react';
import { User, ShieldAlert, ArrowRightCircle } from 'lucide-react';

interface InsiderDealsCardProps {
  data: {
    title: string;
    summaries: string[];
    description: string;
  } | null;
}

const InsiderDealsCard: React.FC<InsiderDealsCardProps> = ({ data }) => {
  if (!data || !data.summaries || data.summaries.length === 0) {
      return (
        <div className="h-full flex items-center justify-center text-xs text-gray-400 italic">
          No Insider Activity
        </div>
      );
  }

  const getTypeStyle = (text: string) => {
      const lower = text.toLowerCase();
      if (lower.includes('acquisition') || lower.includes('buy') || lower.includes('purchase')) {
          return { border: 'border-l-green-500', bg: 'bg-green-50/50', iconColor: 'text-green-600', label: 'Acquisition' };
      }
      if (lower.includes('disposal') || lower.includes('sell') || lower.includes('sold')) {
          return { border: 'border-l-red-500', bg: 'bg-red-50/50', iconColor: 'text-red-600', label: 'Disposal' };
      }
      if (lower.includes('revoke')) {
          return { border: 'border-l-yellow-500', bg: 'bg-yellow-50/50', iconColor: 'text-yellow-600', label: 'Revoke' };
      }
      if (lower.includes('pledge')) {
          return { border: 'border-l-orange-500', bg: 'bg-orange-50/50', iconColor: 'text-orange-600', label: 'Pledge' };
      }
      return { border: 'border-l-gray-300', bg: 'bg-gray-50', iconColor: 'text-gray-400', label: 'Disclosure' };
  };

  const highlightInfo = (text: string) => {
      // Bold Names and Numbers/Dates
      // Note: This regex is approximate based on standard disclosure formats
      return text.split(/(Acquisition|Disposal|Revoke|Pledge|[\d,]+|Rs\.?\s?[\d,.]+)/g).map((part, i) => {
          if (part.match(/^(Acquisition|Disposal|Revoke|Pledge)$/)) return <span key={i} className="font-bold underline">{part}</span>;
          if (part.match(/([\d,]+|Rs\.?\s?[\d,.]+)/)) return <span key={i} className="font-semibold text-gray-900">{part}</span>;
          return <span key={i}>{part}</span>;
      });
  };

  return (
    <div className="h-full overflow-y-auto custom-scrollbar p-1">
        <div className="space-y-3">
            {data.summaries.map((summary, idx) => {
                const style = getTypeStyle(summary);
                return (
                    <div key={idx} className={`pl-3 pr-2 py-2 rounded-r border border-gray-100 border-l-4 ${style.border} ${style.bg} relative`}>
                         <div className="flex justify-between items-center mb-1">
                             <div className="flex items-center gap-1.5">
                                 <User size={12} className={style.iconColor} />
                                 <span className={`text-[9px] font-bold uppercase tracking-wider ${style.iconColor}`}>
                                     {style.label}
                                 </span>
                             </div>
                         </div>
                         <p className="text-[10px] leading-relaxed text-gray-700">
                             {highlightInfo(summary)}
                         </p>
                    </div>
                );
            })}

            {/* Footer Description */}
            {data.description && (
                <div className="mt-4 pt-2 border-t border-gray-100 flex gap-2">
                    <ShieldAlert size={12} className="text-gray-400 shrink-0 mt-0.5" />
                    <p className="text-[9px] text-gray-400 leading-normal">
                        {data.description}
                    </p>
                </div>
            )}
        </div>
    </div>
  );
};

export default InsiderDealsCard;

