  } | null;
}

const FinancialsCard: React.FC<FinancialsCardProps> = ({ data }) => {
  const [view, setView] = useState<'CONSOLIDATED' | 'STANDALONE'>('CONSOLIDATED');

  if (!data) return <div className="text-xs text-gray-400 p-4">No Data</div>;

  // Default to Standalone if Consolidated is missing, or respect selection if data exists
  const activeData = (view === 'CONSOLIDATED' && data.CONSOLIDATED) ? data.CONSOLIDATED : (data.STANDALONE || data.CONSOLIDATED);
  const currentView = (view === 'CONSOLIDATED' && !data.CONSOLIDATED && data.STANDALONE) ? 'STANDALONE' : view;

  if (!activeData) {
     return (
        <div className="h-full flex items-center justify-center text-xs text-gray-400 italic">
          No Financial Data Available
        </div>
     );
  }

  const parseInsight = (text: string) => {
      // Regex to extract Value (e.g., Rs 124,562 Cr or 401 Rs or 6%)
      // Prioritize "Rs ... Cr", then "... Rs", then just number with %
      const valueMatch = text.match(/(Rs\s+[\d,]+(?:\.\d+)?\s+Cr|[\d,]+\s+Rs|[\d,.]+%)/);
      // Regex to extract Growth (e.g., growth of -2.4% YoY)
      const growthMatch = text.match(/growth of\s+([-\d\.]+%)/);

      return {
          value: valueMatch ? valueMatch[0] : '',
          growth: growthMatch ? growthMatch[1] : ''
      };
  };

  const getGrowthIcon = (growth: string, color: string) => {
      if (!growth) return null;
      // Sentiment is provided by color, so we use that for icon direction mostly
      if (color === 'positive') return <TrendingUp size={10} className="text-green-600" />;
      if (color === 'negative') return <TrendingDown size={10} className="text-red-600" />;
      return <Minus size={10} className="text-gray-400" />;
  };

  const renderSection = (title: string, items: InsightItem[] | undefined, icon?: React.ReactNode) => {
      if (!items || items.length === 0) return null;
      return (
          <div className="mb-4">
              <div className="flex items-center gap-1.5 mb-2 text-[10px] font-bold uppercase tracking-wider text-gray-500 border-b border-gray-100 pb-1">
                  {icon}
                  {title}
              </div>
              <div className="space-y-2">
                  {items.map((item, idx) => {
                      const { value, growth } = parseInsight(item.insight_text);
                      // Fallback if parsing fails to get a value
                      const displayValue = value || "-";

                      return (
                          <div key={idx} className="flex justify-between items-start group">
                              <div className="w-[45%] pr-2">
                                  <div className="text-[10px] text-gray-600 font-medium leading-tight" title={item.parameter}>
                                      {item.parameter.replace('Quarterly ', '').replace('Annual ', '')}
                                  </div>
                              </div>
                              <div className="flex-1 flex flex-col items-end">
                                  <div className="font-bold text-xs text-gray-900">{displayValue}</div>
                                  {growth && (
                                      <div className={`flex items-center gap-0.5 text-[9px] font-medium mt-0.5 px-1 rounded-sm ${item.insight_color === 'positive' ? 'bg-green-50 text-green-700' : item.insight_color === 'negative' ? 'bg-red-50 text-red-700' : 'bg-gray-50 text-gray-600'}`}>
                                           {getGrowthIcon(growth, item.insight_color)}
                                           {growth} YoY
                                      </div>
                                  )}
                              </div>
                          </div>
                      );
                  })}
              </div>
          </div>
      );
  };

  return (
    <div className="h-full flex flex-col overflow-hidden">
        {/* Toggle Header */}
        <div className="flex border border-gray-100 rounded-lg overflow-hidden mb-3 shrink-0">
            <button 
                onClick={() => setView('CONSOLIDATED')}
                className={`flex-1 py-1 text-[9px] font-bold uppercase tracking-wider transition-colors ${currentView === 'CONSOLIDATED' ? 'bg-indigo-50 text-indigo-700 shadow-inner' : 'bg-white text-gray-400 hover:text-gray-600'}`}
                disabled={!data.CONSOLIDATED}
                title={!data.CONSOLIDATED ? "No Consolidated Data" : ""}
            >
                Consolidated
            </button>
            <div className="w-px bg-gray-100"></div>
            <button 
                onClick={() => setView('STANDALONE')}
                className={`flex-1 py-1 text-[9px] font-bold uppercase tracking-wider transition-colors ${currentView === 'STANDALONE' ? 'bg-indigo-50 text-indigo-700 shadow-inner' : 'bg-white text-gray-400 hover:text-gray-600'}`}
                disabled={!data.STANDALONE}
                title={!data.STANDALONE ? "No Standalone Data" : ""}
            >
                Standalone
            </button>
        </div>

        <div className="overflow-y-auto custom-scrollbar p-1 flex-1">
            {renderSection("Quarterly Results", activeData.QUARTER, <Coins size={12} className="text-indigo-500"/>)}
            {renderSection("Annual Performance", activeData.ANNUAL, <Coins size={12} className="text-indigo-500"/>)}
